request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?created ?org ?orgLabel WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org rdfs:label ?orgLabel . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sf ?sfName ?sourceName ?targetName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?sf a bbo:SequenceFlow .
  ?sf tai:belongsTo ?choreo .
  OPTIONAL { ?sf bbo:name ?sfName . }
  ?sf bbo:has_sourceRef ?source .
  ?sf bbo:has_targetRef ?target .
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  FILTER(EXISTS {
    ?source a ?sType .
    FILTER(?sType IN (bboExt:ExclusiveGateway, bboExt:EventBasedGateway))
  })
}
